<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">prompt</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">&gt; </span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;">./thread</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> 100000</span></span>
